1	/* ---------------------------------------------------------------------------
2	 * tokens.css — operator's portfolio
3	 * Canonical custom properties. Consumed by every component.
4	 * Dark is canonical; light is opt-in (toggle implemented separately).
5	 *
6	 * Vertical rhythm rule (suite 13/P03):
7	 *   All vertical spacing between content blocks is a multiple of
8	 *   var(--s-2) (8px). Text within a block follows the line-height
9	 *   of its type role. This rule is for prose; UI elements may use
10	 *   finer increments via the --s-* scale.
11	 * --------------------------------------------------------------------------- */
12	
13	:root,
14	:root[data-theme="dark"] {
15	  /* ----- v2 semantic colour palette (suite 13/P02) -----
16	     Dark is canonical. Hex with alpha (#RRGGBBAA) keeps tokens
17	     self-contained — no rgba(). All fg/bg pairs documented in
18	     docs/v2_audit.md ## Contrast deviations meet WCAG AA. */
19	
20	  /* surface */
21	  --bg:           #0c0e10;            /* base background          */
22	  --bg-mute:      #14171a;            /* muted surface            */
23	  --bg-raise:     #1b1f23;            /* raised surface (cards)   */
24	  --bg-overlay:   #06070824;          /* modal overlay            */
25	
26	  /* foreground */
27	  --fg:           #e8e6e1;            /* primary text             */
28	  --fg-mute:      #8b8a85;            /* secondary text           */
29	  --fg-faint:     #6e6e68;            /* tertiary text — adjusted from #5a5a55 to clear AA-large (see audit) */
30	  --fg-inverse:   #0c0e10;            /* text on accent surface   */
31	
32	  /* borders + dividers */
33	  --line:         #232629;            /* hairline                 */
34	  --line-strong:  #3a3d40;            /* emphatic border          */
35	
36	  /* accent — warm gold/amber inherited from v1 (B3). Do not change without authorization. */
37	  --accent:       #c9a96e;            /* primary accent (mono)    */
38	  --accent-mute:  #c9a96e22;          /* hover/wash               */
39	  --accent-fg:    #0c0e10;            /* text on accent           */
40	
41	  /* status — used sparingly (chat error states only) */
42	  --warn:         #d18b3a;
43	  --error:        #dc6e69;            /* adjusted from #d2615c to clear AA on bg-raise (see audit) */
44	  --ok:           #6da16a;
45	
46	  /* ----- v1 aliases (transitional) -------------------------
47	     Active components in src/components/* still reference v1
48	     names. Aliases map them onto the v2 palette so the visual
49	     ramp degrades gracefully until each component is migrated
50	     in subsequent suite-13 prompts. New code MUST consume the
51	     semantic v2 tokens above; do not introduce new --bg-N or
52	     --fg-hi/dim references. */
53	  --bg-0:        var(--bg);
54	  --bg-1:        var(--bg-mute);
55	  --bg-2:        var(--bg-raise);
56	  --bg-3:        var(--line);
57	  --rule:        var(--line);
58	  --fg-hi:       var(--fg);
59	  --fg-dim:      var(--fg-mute);
60	  --accent-dim:  var(--accent-mute);
61	  --danger:      var(--error);
62	
63	  /* type stacks — two faces, period. mono for technical + headlines,
64	     serif for long-form. --font-mono / --font-serif are injected by
65	     next/font on <html>; the tokens below are the consumable stacks. */
66	  --t-mono:  var(--font-mono),  ui-monospace, monospace;
67	  --t-serif: var(--font-serif), Georgia, serif;
68	
69	  /* type scale — base 16px, ratio 1.25, 7 steps */
70	  --t-sm-size:    13px;  --t-sm-lh:    20px;
71	  --t-base-size:  16px;  --t-base-lh:  26px;
72	  --t-md-size:    18px;  --t-md-lh:    28px;
73	  --t-lg-size:    22px;  --t-lg-lh:    32px;
74	  --t-xl-size:    28px;  --t-xl-lh:    36px;
75	  --t-2xl-size:   36px;  --t-2xl-lh:   44px;
76	  --t-3xl-size:   48px;  --t-3xl-lh:   56px;
77	
78	  /* tracking */
79	  --t-tight:  -0.01em;
80	  --t-normal: 0;
81	  --t-wide:   0.05em;
82	
83	  /* spacing — single 4px-grid scale (suite 13/P03). All spacing in v2
84	     components draws from --s-1..--s-10. See vertical-rhythm rule at
85	     the top of this file. */
86	  --s-1:   4px;
87	  --s-2:   8px;
88	  --s-3:   12px;
89	  --s-4:   16px;
90	  --s-5:   24px;
91	  --s-6:   32px;
92	  --s-7:   48px;
93	  --s-8:   64px;
94	  --s-9:   96px;
95	  --s-10:  128px;
96	
97	  /* layout containers — three widths cover the v2 surface area:
98	     narrow for prose/chat, base for project pages, wide for landing
99	     teaser grids. Container.tsx is the only consumer. */
100	  --container-narrow:  640px;
101	  --container-base:    900px;
102	  --container-wide:    1200px;
103	
104	  /* borders */
105	  --r-0: 0;
106	  --r-1: 2px;
107	  --border-hair:   1px solid var(--rule);
108	  --border-double: 3px double var(--rule);
109	
110	  /* z-index semantic */
111	  --z-rail:      40;
112	  --z-statusbar: 50;
113	  --z-palette:   80;
114	  --z-toast:     90;
115	  --z-boot:     100;
116	
117	  /* motion vocabulary (suite 13/P04) — five durations, three curves.
118	     Functional motion only: every animation has a no-motion path via the
119	     reduced-motion block at the bottom of this file. See
120	     docs/v2_motion_guide.md for the use-case map. */
121	  --d-instant: 0ms;     /* state change with no animation        */
122	  --d-tap:     80ms;    /* button press feedback                 */
123	  --d-fast:    160ms;   /* focus ring, hover state               */
124	  --d-norm:    280ms;   /* page transition fade                  */
125	  --d-slow:    480ms;   /* chat message arrival                  */
126	
127	  --ease-out:    cubic-bezier(0.16, 1, 0.3, 1);    /* decelerate to rest */
128	  --ease-in-out: cubic-bezier(0.4, 0, 0.2, 1);     /* state toggles      */
129	  --ease-linear: linear;                            /* text streaming    */
130	
131	  /* legacy motion aliases (transitional) — components in src/components/*
132	     and src/_legacy_v1/* still reference --d-flash, --d-accordion, --ease,
133	     --ease-accordion. Aliased onto the v2 motion vocabulary so existing
134	     timings degrade gracefully until each component is migrated. New code
135	     MUST consume the v2 tokens above. */
136	  --d-flash:        var(--d-fast);
137	  --d-accordion:    var(--d-slow);
138	  --ease:           var(--ease-out);
139	  --ease-accordion: var(--ease-out);
140	
141	  /* layout */
142	  --statusbar-h: 0px; /* R04: status bar removed; reserved height collapses */
143	  --toprail-h:   32px;
144	  --keycap-size: 36px;
145	  --measure-prose: 72ch;
146	  --measure-book:  64ch;
147	
148	  color-scheme: dark;
149	}
150	
151	/* light: explicit attribute override of dark default (see B1).
152	   prefers-color-scheme is intentionally NOT used here so the
153	   theme toggle (suite 14/P07) can override the OS preference. */
154	:root[data-theme="light"] {
155	  /* surface */
156	  --bg:           #fbfaf8;
157	  --bg-mute:      #f1efeb;
158	  --bg-raise:     #ffffff;
159	  --bg-overlay:   #00000018;
160	
161	  /* foreground */
162	  --fg:           #1a1a1a;
163	  --fg-mute:      #555550;
164	  --fg-faint:     #888880;
165	  --fg-inverse:   #fbfaf8;
166	
167	  /* borders + dividers */
168	  --line:         #e3e0d8;
169	  --line-strong:  #c8c4b8;
170	
171	  /* accent */
172	  --accent:       #8a6a2a;
173	  --accent-mute:  #8a6a2a18;
174	  --accent-fg:    #fbfaf8;
175	
176	  /* status */
177	  --warn:         #a35e08;            /* adjusted from #b46a0a to clear AA normal (see audit) */
178	  --error:        #a73a35;
179	  --ok:           #3f6e3a;
180	
181	  /* v1 aliases (see dark block) */
182	  --bg-0:        var(--bg);
183	  --bg-1:        var(--bg-mute);
184	  --bg-2:        var(--bg-raise);
185	  --bg-3:        var(--line);
186	  --rule:        var(--line);
187	  --fg-hi:       var(--fg);
188	  --fg-dim:      var(--fg-mute);
189	  --accent-dim:  var(--accent-mute);
190	  --danger:      var(--error);
191	
192	  color-scheme: light;
193	}
194	
195	/* prefers-reduced-motion: collapse all non-instant durations.
196	   --d-instant is intentionally absent (already 0). Aliases (--d-flash,
197	   --d-accordion) inherit zero through their var() chain. */
198	@media (prefers-reduced-motion: reduce) {
199	  :root { --d-tap:  0ms; }
200	  :root { --d-fast: 0ms; }
